// Generated by OrchestKit Claude Plugin
// Created: 2026-04-27

/**
 * UI Change Detector — PostToolUse hook (M125 #2)
 *
 * Watches Edit/Write on UI-shaped files. When detected and the dev stack is
 * live, emits an `additionalContext` nudge prompting the user to run /ork:expect
 * on the affected route. Diff-aware (single route per change), debounced, and
 * skippable per-session.
 *
 * Trigger files: *.tsx, *.jsx, *.css, *.scss, app/**\/page.tsx, pages/**\/*.tsx
 *
 * Skip:
 *   - ORK_EXPECT_AUTO=0          (env-level opt-out)
 *   - .claude/state/expect-skip.<sessionId>  (session-level skip token)
 *   - last fire on same route < 30s ago (per-route cooldown)
 *   - dev stack not live          (graceful no-op)
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import type { HookInput, HookResult } from '../types.js';
import { outputSilentSuccess, outputAllowWithContext, getField } from '../lib/common.js';
import { getProjectDir, getSessionId } from './../lib/env.js';
import { isDevStackLive, readDevStackState } from '../lib/dev-stack-state.js';

const COOLDOWN_MS = 30_000;
const FIRE_RECORD = '.claude/state/expect-auto-fires.json';

// Stale entries (old sessions, legacy un-keyed routes) are pruned on write
// so the per-session keying (#2919) can't grow the file unboundedly.
const PRUNE_AFTER_MS = 3_600_000; // 1h — far beyond any live cooldown

interface FireRecord {
  [sessionAndRoute: string]: number; // "<sid>:<route>" → last fire timestamp (ms)
}

function readFires(projectDir: string): FireRecord {
  const path = join(projectDir, FIRE_RECORD);
  if (!existsSync(path)) return {};
  try {
    return JSON.parse(readFileSync(path, 'utf8')) as FireRecord;
  } catch {
    return {};
  }
}

function writeFires(projectDir: string, fires: FireRecord): void {
  const filePath = join(projectDir, FIRE_RECORD);
  mkdirSync(dirname(filePath), { recursive: true });
  writeFileSync(filePath, JSON.stringify(fires));
}

/**
 * Map a UI file path to a route. Best-effort; returns null when uncertain.
 *
 * Examples:
 *   app/dashboard/page.tsx          → /dashboard
 *   app/(marketing)/pricing/page.tsx → /pricing  (route groups stripped)
 *   pages/settings.tsx              → /settings
 *   pages/api/users.ts              → null (API route, no UI)
 *   src/components/Button.tsx       → /         (component — test homepage)
 *   styles/main.css                 → /         (global style — test homepage)
 */
export function fileToRoute(filePath: string): string | null {
  const normalized = filePath.replace(/\\/g, '/');

  // Next.js App Router (app/.../page.tsx)
  const appMatch = normalized.match(/(?:^|\/)app\/(.+)\/page\.(tsx|jsx)$/);
  if (appMatch) {
    const segments = appMatch[1]
      .split('/')
      .filter((s) => !s.startsWith('(') || !s.endsWith(')')); // strip route groups
    return `/${segments.join('/').replace(/^\/$/, '')}`;
  }

  // Next.js Pages Router (pages/.../foo.tsx, exclude pages/api/*)
  const pagesMatch = normalized.match(/(?:^|\/)pages\/(?!api\/)(.+)\.(tsx|jsx)$/);
  if (pagesMatch) {
    let route = pagesMatch[1];
    if (route === 'index') return '/';
    if (route.endsWith('/index')) route = route.slice(0, -'/index'.length);
    return `/${route}`;
  }

  // Component / global style — test homepage as proxy
  if (/\.(tsx|jsx|css|scss)$/.test(normalized)) return '/';

  return null;
}

const UI_EXT_RE = /\.(tsx|jsx|css|scss)$/;

export async function uiChangeDetector(input: HookInput): Promise<HookResult> {
  // Fast guard: only after Edit / Write
  const tool = input.tool_name;
  if (tool !== 'Edit' && tool !== 'Write') return outputSilentSuccess();

  // Env-level opt-out
  if (process.env.ORK_EXPECT_AUTO === '0') return outputSilentSuccess();

  // File guard
  const filePath = getField<string>(input, 'tool_input.file_path');
  if (typeof filePath !== 'string' || !UI_EXT_RE.test(filePath)) return outputSilentSuccess();

  // Session-skip token
  const sessionId = getSessionId();
  const projectDir = getProjectDir();
  const skipPath = join(projectDir, '.claude', 'state', `expect-skip.${sessionId}`);
  if (existsSync(skipPath)) return outputSilentSuccess();

  // Dev stack must be live (graceful no-op otherwise)
  if (!isDevStackLive()) return outputSilentSuccess();

  // Compute route
  const route = fileToRoute(filePath);
  if (!route) return outputSilentSuccess();

  // Per-route cooldown, scoped to this session (#2919): the skip token above
  // is already session-keyed; the cooldown sharing one key across sessions
  // silently swallowed the nudge for whichever session edited second.
  const now = Date.now();
  const fires = readFires(projectDir);
  const fireKey = `${sessionId}:${route}`;
  const last = fires[fireKey] ?? 0;
  if (now - last < COOLDOWN_MS) return outputSilentSuccess();

  for (const key of Object.keys(fires)) {
    if (now - (fires[key] ?? 0) > PRUNE_AFTER_MS) delete fires[key];
  }
  fires[fireKey] = now;
  writeFires(projectDir, fires);

  const state = readDevStackState();
  const url = state ? `${state.baseUrl}${route}` : route;

  return outputAllowWithContext(
    `UI change detected on \`${filePath}\` → route \`${route}\`. ` +
      `Run \`/ork:expect ${route}\` against ${url} to verify, or write \`SKIP\` to ` +
      `\`.claude/state/expect-skip.${sessionId}\` to silence for the session. ` +
      `Cooldown: 30s per route.`
  );
}
